const CircuitBreaker = require('opossum');
const axios = require('axios');

async function callService(url) {
  return axios.get(url);
}

const breaker = new CircuitBreaker(callService, {
  timeout: 2000,
  errorThresholdPercentage: 50,
  resetTimeout: 15000
});

breaker.fallback(() => ({ data: 'fallback' }));

module.exports = async function fetch(url) {
  try {
    const res = await breaker.fire(url);
    return res.data;
  } catch (err) {
    console.error('Call failed or breaker open', err.message);
    throw err;
  }
};
